BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?tmtReq ?tmtReqName ?ownerPkg ?ownerPkgName WHERE {
  ?tmtReq rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?tmtReq vocab:NamedElement_name ?tmtReqName . }
  OPTIONAL { ?tmtReq vocab:Element_owner+ ?ownerPkg .
             ?ownerPkg rdf:type vocab:package .
             OPTIONAL { ?ownerPkg vocab:NamedElement_name ?ownerPkgName . }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?ownerPkg ?ownerPkgName ?imp ?impName WHERE {
  ?tmtReq rdf:type vocab:tmt%20requirement .
  ?tmtReq vocab:Element_owner+ ?ownerPkg .
  ?ownerPkg rdf:type vocab:package .
  OPTIONAL { ?ownerPkg vocab:NamedElement_name ?ownerPkgName . }

  ?ownerPkg ?impPred ?imp .
  FILTER(CONTAINS(LCASE(STR(?impPred)), "import"))

  OPTIONAL { ?imp vocab:NamedElement_name ?impName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkgImport ?pkgImportName ?importedPackage ?importedPackageName ?importingNamespaceName WHERE {
  ?pkgImport rdf:type vocab:Package%20import .
  OPTIONAL { ?pkgImport vocab:NamedElement_name ?pkgImportName . }

  OPTIONAL { ?pkgImport vocab:PackageImport_importedPackage ?importedPackage . }
  OPTIONAL { ?importedPackage vocab:NamedElement_name ?importedPackageName . }

  OPTIONAL {
    ?pkgImport vocab:PackageImport_importingNamespace ?importingNamespace .
    ?importingNamespace vocab:NamedElement_name ?importingNamespaceName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?p ?o ?oType ?oName WHERE {
  ?s vocab:Package_import ?o .
  BIND(vocab:Package_import AS ?p)
  OPTIONAL { ?o rdf:type ?oType . }
  OPTIONAL { ?o vocab:NamedElement_name ?oName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkgImport ?importedPackage ?importedPackageName ?importingNamespace ?importingNamespaceName WHERE {
  ?pkgImport rdf:type vocab:package%20import .
  OPTIONAL { ?pkgImport vocab:PackageImport_importedPackage ?importedPackage . }
  OPTIONAL { ?importedPackage vocab:NamedElement_name ?importedPackageName . }
  OPTIONAL { ?pkgImport vocab:PackageImport_importingNamespace ?importingNamespace . }
  OPTIONAL { ?importingNamespace vocab:NamedElement_name ?importingNamespaceName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?tmtReq ?tmtReqName WHERE {
  ?tmtReq rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?tmtReq vocab:NamedElement_name ?tmtReqName . }
  FILTER(
    CONTAINS(LCASE(STR(?tmtReq)), "doors") ||
    CONTAINS(LCASE(STR(?tmtReq)), "drd")
  )
}
LIMIT 25
